import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion'; // Note: Add framer-motion if desired, or use CSS

// Enhanced movie poster fallback
const fallbackImages = [
  'https://images.unsplash.com/photo-1489599849228-13e67d91ebff?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1517604931442-7e0c6ed2963c?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1594908900066-3f47337549d8?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1493225457124-a3eb161ffa5f?w=300&h=450&fit=crop',
  'https://images.unsplash.com/photo-1513941231169-2b8d6ce5dd21?w=300&h=450&fit=crop',
];

const getFallbackImage = () => fallbackImages[Math.floor(Math.random() * fallbackImages.length)];

const MovieManager = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [filterRating, setFilterRating] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  // Upload state
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [previewImage, setPreviewImage] = useState(null);
  const [uploadedPoster, setUploadedPoster] = useState('');
  const fileInputRef = useRef(null);

  const [formData, setFormData] = useState({
    title: '',
    genre: '',
    rating: '',
    recommendation: 'Yes'
  });

  useEffect(() => {
    fetchMovies();
  }, [filterRating]);

  const fetchMovies = async () => {
    setLoading(true);
    try {
      const url = filterRating ? `http://localhost:5000/movies?rating=${filterRating}` : 'http://localhost:5000/movies';
      const response = await fetch(url);
      const data = await response.json();
      setMovies(data);
    } catch (error) {
      console.error('Error fetching movies:', error);
      alert('Failed to fetch movies');
    }
    setLoading(false);
  };

  const handleImageUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    // Preview
    const reader = new FileReader();
    reader.onloadend = () => {
      setPreviewImage(reader.result);
    };
    reader.readAsDataURL(file);

    setUploading(true);
    const formDataUpload = new FormData();
    formDataUpload.append('poster', file);

    try {
      const response = await fetch('http://localhost:5000/movies/upload', {
        method: 'POST',
        body: formDataUpload,
      });

      const result = await response.json();
      if (response.ok) {
        setUploadedPoster(result.path);
        setUploadProgress(100);
        alert('Image uploaded! Use the path in form.');
      } else {
        alert(result.error || 'Upload failed');
      }
    } catch (error) {
      alert('Upload failed: ' + error.message);
    }
    setUploading(false);
    setUploadProgress(0);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.title || !formData.genre || !formData.rating) {
      alert('All fields are required');
      return;
    }

    try {
      const submitData = {
        title: formData.title,
        genre: formData.genre,
        rating: parseInt(formData.rating),
        recommendation: formData.recommendation,
        poster: uploadedPoster || null
      };

      if (editingId) {
        const response = await fetch(`http://localhost:5000/movies/${editingId}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const updated = await response.json();
        setMovies(movies.map(m => m.id === editingId ? updated : m));
      } else {
        const response = await fetch('http://localhost:5000/movies', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(submitData)
        });
        const newMovie = await response.json();
        setMovies([...movies, newMovie]);
      }
      resetForm();
    } catch (error) {
      console.error('Error saving movie:', error);
      alert('Failed to save movie');
    }
  };

  const resetForm = () => {
    setShowForm(false);
    setEditingId(null);
    setFormData({ title: '', genre: '', rating: '', recommendation: 'Yes' });
    setPreviewImage(null);
    setUploadedPoster('');
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleEdit = (movie) => {
    setFormData({
      title: movie.title,
      genre: movie.genre,
      rating: movie.rating,
      recommendation: movie.recommendation
    });
    setUploadedPoster(movie.poster || '');
    setEditingId(movie.id);
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure?')) return;
    try {
      await fetch(`http://localhost:5000/movies/${id}`, { method: 'DELETE' });
      setMovies(movies.filter(m => m.id !== id));
    } catch (error) {
      alert('Delete failed');
    }
  };

  const filteredMovies = movies.filter(movie => 
    movie.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    movie.genre.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const genreColors = {
    'Sci-Fi': 'from-blue-500/20 to-cyan-500/20 backdrop-blur-sm',
    'Action': 'from-red-500/20 to-orange-500/20 backdrop-blur-sm',
    'Drama': 'from-purple-500/20 to-pink-500/20 backdrop-blur-sm',
    'Comedy': 'from-yellow-500/20 to-orange-500/20 backdrop-blur-sm',
    'Horror': 'from-gray-800/50 to-red-500/20 backdrop-blur-sm',
    'Romance': 'from-pink-500/20 to-rose-500/20 backdrop-blur-sm',
  };

  const getRatingColor = (rating) => rating >= 4 ? 'text-green-400' : rating >= 3 ? 'text-yellow-400' : 'text-red-400';

  return (
    <div className="w-full p-6">
      {/* Header */}
      <motion.div 
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        className="mb-12"
      >
        <div className="flex items-center justify-between mb-8">
          <div>
            <h2 className="text-5xl font-black bg-gradient-to-r from-yellow-400 via-yellow-500 to-orange-400 bg-clip-text text-transparent drop-shadow-lg">
              🎞️ Movie Collection
            </h2>
            <p className="text-xl text-gray-400 mt-2">Upload custom posters & organize your favorites</p>
          </div>
          <motion.button
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setShowForm(!showForm)}
            className="group bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-black py-4 px-10 rounded-2xl shadow-2xl hover:shadow-emerald-500/50 transition-all duration-300 border border-emerald-400/30"
          >
            <span className="flex items-center gap-2">
              + Add Movie 
              <motion.div 
                animate={{ rotate: showForm ? 45 : 0 }}
                className="w-5 h-5 bg-white/20 rounded-full group-hover:bg-white/30 transition-all" 
              />
            </span>
          </motion.button>
        </div>

        {/* Search & Filter */}
        <div className="flex flex-col sm:flex-row gap-4 bg-white/5 backdrop-blur-xl p-6 rounded-3xl border border-white/10 shadow-2xl">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="🔍 Search movies by title or genre..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full bg-white/10 border border-white/20 rounded-2xl px-12 py-4 text-white placeholder-gray-400 focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300 text-lg"
            />
          </div>
          <select
            value={filterRating}
            onChange={(e) => setFilterRating(e.target.value)}
            className="bg-white/10 border border-white/20 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300"
          >
            <option value="">All Ratings</option>
            {[...Array(5)].map((_, i) => (
              <option key={i+1} value={i+1}>{Array(i+1).fill('⭐').join('')}</option>
            ))}
          </select>
        </div>
      </motion.div>

      {/* Upload & Form */}
      <AnimatePresence>
        {showForm && (
          <motion.div
            initial={{ opacity: 0, y: 50, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 50, scale: 0.95 }}
            className="backdrop-blur-xl bg-white/5 border border-white/10 rounded-3xl p-10 mb-12 shadow-2xl hover:shadow-3xl transition-all duration-500"
          >
            <h3 className="text-3xl font-black text-white mb-8 bg-gradient-to-r from-purple-400 to-pink-400 bg-clip-text text-transparent">
              {editingId ? '✏️ Edit Movie' : '🎬 Add New Movie'}
            </h3>
            
            {/* Image Upload */}
            <div className="mb-8">
              <label className="block text-gray-300 font-black mb-4 text-xl">🖼️ Movie Poster</label>
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
                <div className="space-y-4">
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept="image/*"
                    onChange={handleImageUpload}
                    className="w-full bg-white/10 border-2 border-dashed border-white/30 rounded-2xl p-8 text-white file:mr-4 file:py-3 file:px-6 file:rounded-xl file:border-0 file:bg-gradient-to-r file:from-yellow-500 file:to-orange-500 file:text-white file:font-bold file:cursor-pointer hover:border-yellow-400/50 transition-all duration-300 cursor-pointer"
                  />
                  {uploading && (
                    <div className="w-full bg-gray-700 rounded-full h-3">
                      <div 
                        className="bg-gradient-to-r from-emerald-500 to-teal-500 h-3 rounded-full transition-all duration-300"
                        style={{ width: `${uploadProgress}%` }}
                      />
                    </div>
                  )}
                  {uploadedPoster && (
                    <div className="text-emerald-400 font-bold text-sm">
                      ✅ Uploaded: {uploadedPoster.split('/').pop()}
                    </div>
                  )}
                </div>
                {previewImage && (
                  <div className="relative">
                    <img src={previewImage} alt="Preview" className="w-full max-h-64 object-cover rounded-2xl shadow-2xl" />
                    <div className="absolute -top-2 -right-2 bg-emerald-500 text-white px-3 py-1 rounded-full text-xs font-bold">
                      Preview
                    </div>
                  </div>
                )}
              </div>
            </div>

            {/* Form Fields */}
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <div>
                  <label className="block text-gray-300 font-black mb-3 text-lg">Movie Title</label>
                  <input
                    type="text"
                    placeholder="Enter movie title..."
                    value={formData.title}
                    onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                    className="w-full bg-white/10 backdrop-blur-sm border border-white/20 rounded-2xl px-6 py-4 text-white placeholder-gray-400 focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300 text-lg font-semibold"
                  />
                </div>
                <div>
                  <label className="block text-gray-300 font-black mb-3 text-lg">Genre</label>
                  <input
                    type="text"
                    placeholder="Action, Sci-Fi, Drama..."
                    value={formData.genre}
                    onChange={(e) => setFormData({ ...formData, genre: e.target.value })}
                    className="w-full bg-white/10 backdrop-blur-sm border border-white/20 rounded-2xl px-6 py-4 text-white placeholder-gray-400 focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300"
                  />
                </div>
              </div>
              <div className="space-y-4">
                <div>
                  <label className="block text-gray-300 font-black mb-3 text-lg">Rating</label>
                  <input
                    type="number"
                    min="1"
                    max="5"
                    placeholder="1-5"
                    value={formData.rating}
                    onChange={(e) => setFormData({ ...formData, rating: e.target.value })}
                    className="w-full bg-white/10 backdrop-blur-sm border border-white/20 rounded-2xl px-6 py-4 text-white placeholder-gray-400 focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300 text-2xl font-black text-yellow-400"
                  />
                </div>
                <div>
                  <label className="block text-gray-300 font-black mb-3 text-lg">Recommendation</label>
                  <select
                    value={formData.recommendation}
                    onChange={(e) => setFormData({ ...formData, recommendation: e.target.value })}
                    className="w-full bg-white/10 backdrop-blur-sm border border-white/20 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-yellow-400/50 focus:ring-4 focus:ring-yellow-400/20 transition-all duration-300 font-semibold"
                  >
                    <option value="Yes">✓ Yes - Highly Recommend</option>
                    <option value="No">✗ No - Skip It</option>
                  </select>
                </div>
              </div>
              
              <div className="md:col-span-2 flex flex-col sm:flex-row gap-4 pt-4">
                <motion.button
                  type="submit"
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  className="flex-1 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white font-black py-5 px-8 rounded-2xl shadow-2xl hover:shadow-emerald-500/50 transition-all duration-300 border border-emerald-400/30 text-lg"
                >
                  {editingId ? '💾 Update Movie' : '🎬 Add Movie'}
                </motion.button>
                <motion.button
                  type="button"
                  onClick={resetForm}
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  className="flex-1 bg-gradient-to-r from-gray-700/50 to-gray-800/50 hover:from-gray-600 hover:to-gray-700 text-white font-black py-5 px-8 rounded-2xl shadow-xl hover:shadow-gray-500/30 transition-all duration-300 border border-gray-500/30 text-lg"
                >
                  ❌ Cancel
                </motion.button>
              </div>
            </form>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Movies Grid */}
      <div className="space-y-8">
        {loading ? (
          <div className="flex justify-center items-center h-80">
            <motion.div 
              animate={{ rotate: 360 }}
              transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
              className="w-20 h-20 border-4 border-yellow-500/20 border-t-yellow-500 rounded-full"
            />
          </div>
        ) : filteredMovies.length === 0 ? (
          <motion.div 
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            className="text-center py-24 bg-gradient-to-b from-white/5 to-transparent rounded-3xl border-2 border-dashed border-yellow-500/20 backdrop-blur-xl"
          >
            <div className="text-8xl mb-6">🎥</div>
            <h3 className="text-3xl font-black text-white mb-4">No Movies Found</h3>
            <p className="text-xl text-gray-400 max-w-md mx-auto">Try adjusting your search or rating filter, or add your first movie!</p>
          </motion.div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5 gap-8">
            {filteredMovies.map((movie, index) => (
              <motion.div
                key={movie.id}
                initial={{ opacity: 0, y: 50 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.05 }}
                whileHover={{ y: -10, scale: 1.02 }}
                className="group relative bg-gradient-to-br from-slate-800/80 to-slate-900/50 backdrop-blur-xl rounded-3xl p-8 border border-white/10 hover:border-yellow-400/30 shadow-2xl hover:shadow-yellow-500/20 transition-all duration-500 overflow-hidden"
              >
                {/* Poster */}
                <div className="relative mb-6 h-80 rounded-2xl overflow-hidden bg-gradient-to-br from-gray-900/50 to-transparent group-hover:ring-4 group-hover:ring-yellow-400/20">
                  <img 
                    src={movie.poster ? `http://localhost:5000${movie.poster}` : getFallbackImage()}
                    alt={movie.title}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
                    onError={(e) => {
                      e.target.src = getFallbackImage();
                    }}
                  />
                  <div className={`absolute inset-0 bg-gradient-to-t ${genreColors[movie.genre] || 'from-gray-900/70'} opacity-0 group-hover:opacity-100 transition-opacity duration-500`} />
                  <div className="absolute top-4 left-4 z-10">
                    <span className="px-4 py-2 rounded-full text-xs font-black bg-white/20 backdrop-blur-sm text-white">
                      {movie.genre}
                    </span>
                  </div>
                  <div className={`absolute top-4 right-4 z-10 ${getRatingColor(movie.rating)} px-4 py-2 rounded-full text-sm font-black bg-white/20 backdrop-blur-sm shadow-lg`}>
                    {'⭐'.repeat(movie.rating)}
                  </div>
                </div>

                {/* Content */}
                <h3 className="text-2xl font-black text-white mb-3 line-clamp-2 group-hover:text-yellow-400 transition-colors">
                  {movie.title}
                </h3>
                
                <div className="space-y-3 mb-8 text-gray-300 text-sm">
                  <div className="flex items-center justify-between">
                    <span>Rating:</span>
                    <span className="font-black text-yellow-400 text-lg">{movie.rating}/5</span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span>Recommend:</span>
                    <span className={`font-black px-3 py-1 rounded-full text-xs ${movie.recommendation === 'Yes' ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-400/30' : 'bg-red-500/20 text-red-400 border border-red-400/30'}`}>
                      {movie.recommendation}
                    </span>
                  </div>
                  {movie.poster && (
                    <div className="text-xs opacity-75 truncate">
                      📸 Custom poster uploaded
                    </div>
                  )}
                </div>

                {/* Actions */}
                <div className="flex gap-3 pt-4 border-t border-white/10">
                  <motion.button
                    onClick={() => handleEdit(movie)}
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    className="flex-1 bg-gradient-to-r from-blue-500/80 to-blue-600/80 hover:from-blue-600 hover:to-blue-700 text-white font-black py-4 px-6 rounded-xl backdrop-blur-sm border border-blue-400/30 shadow-xl hover:shadow-blue-500/30 transition-all duration-300"
                  >
                    ✏️ Edit
                  </motion.button>
                  <motion.button
                    onClick={() => handleDelete(movie.id)}
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    className="flex-1 bg-gradient-to-r from-red-500/80 to-red-600/80 hover:from-red-600 hover:to-red-700 text-white font-black py-4 px-6 rounded-xl backdrop-blur-sm border border-red-400/30 shadow-xl hover:shadow-red-500/30 transition-all duration-300"
                  >
                    🗑️ Delete
                  </motion.button>
                </div>
              </motion.div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default MovieManager;
